-- ============================================================================
-- FICSIT Foreman — LITE EEPROM  v0.3.2   (GENERATED by tools/bundle.py)
-- Standalone early-game controller. No Internet Card, no hard drive, no upgrades.
-- Paste this whole file into a Computer Case EEPROM, then declare your factory in
-- the TOPOLOGY table below (see examples/topology.example.lua) and hand-name your
-- containers <Item>_<Keyword>_<N>. To run the FULL build later, paste the separate
-- foreman-loader.lua instead — LITE and FULL are independent, separately-versioned.
-- ============================================================================
local LITE_VERSION = "0.3.2"

-- Paste-and-go: leave TOPOLOGY nil and the controller auto-discovers the belt graph
-- (crawls getFactoryConnectors -> getConnected -> owner) and reads each container's
-- role/item/target from its nick. Only set a TOPOLOGY table if you want to declare it
-- by hand (or set the global FOREMAN_TOPOLOGY).
local TOPOLOGY = FOREMAN_TOPOLOGY or nil

local _preload, _cache = {}, {}
local function require(n)
  if _cache[n] then return _cache[n] end
  local m = _preload[n](); _cache[n] = m; return m
end
_preload["discover"] = function()
-- discover.lua — automatic topology discovery for FICSIT Foreman (PRODUCT code).
--
-- FIN CAN see a building's belt neighbours: getFactoryConnectors() -> each
-- FactoryConnection has .direction (0=in,1=out) + .isConnected; :getConnected()
-- returns the peer connection, and .owner (from ActorComponent) is the building it
-- belongs to (a network component with .id). So one computer can crawl the whole
-- connected belt graph and rebuild the topology Foreman otherwise expects declared —
-- a link-state crawl (the single-computer analogue of OSPF).
--
--   Discover.run({ find=?, getProxy=? }) -> { containers, splitters, mergers,
--                                             constructors, belts }
--
-- belts = { {from=id, fromOutput=n, to=id, toInput=n}, ... } keyed by component UUID,
-- ready to hand to Router.new / Planner. Roles come from the component type; item
-- types/roles still come from container nicks (input/output/buffer) + recipes.

local Discover = {}

local INPUT, OUTPUT = 0, 1

-- The set of function internal-names a component exposes, gathered from its class
-- HIERARCHY via reflection: getType() -> getFunctions() / getParent(). This is the
-- only WARNING-FREE way to know a component's capabilities in-game:
--   * tostring(getType()) is "Object<Class>: <hash>" — NO usable class name (verified
--     in-game), so name matching is impossible.
--   * accessing a missing INSTANCE member (p.getOutput on a container) logs
--     "No property/function found. Nil return is deprecated and will become an error" —
--     so we must NOT probe instance members.
-- getFunctions()/function.name DO work, so we ask the class what it can do instead.
function Discover.funcSet(p)
  local set = {}
  if not p or not p.getType then return set end
  local ok, cls = pcall(function() return p:getType() end)
  if not ok then return set end
  local guard = 0
  while cls and guard < 16 do
    guard = guard + 1
    local okf, fns = pcall(function() return cls:getFunctions() end)
    if okf and type(fns) == "table" then
      for _, f in ipairs(fns) do
        local okn, nm = pcall(function() return f.name end)
        if okn and nm ~= nil then set[tostring(nm)] = true
        elseif type(f) == "string" then set[f] = true end   -- emulator shape: plain names
      end
    end
    local okp, par = pcall(function() return cls:getParent() end)
    if not okp then break end
    cls = par
  end
  return set
end

-- Classify a live component proxy by its capability FUNCTION SET (reflection-derived,
-- warning-free). In this FIN version (verified in-game):
--   getRecipes            -> a manufacturer (constructor/assembler/foundry/…)
--   transferItem+canOutput-> a CodeableSplitter  (splitter HAS canOutput)
--   transferItem (no canOutput) -> a CodeableMerger  (merger has NO canOutput, and
--                            NEITHER has getOutput — the old getOutput probe made every
--                            splitter look like a merger, which killed all routing)
--   getInventories        -> a storage container or A.W.E.S.O.M.E. Sink
--   stopComputer          -> the computer itself (has getInventories too) — NOT a node
function Discover.classify(p)
  local f = Discover.funcSet(p)
  if f.stopComputer then return nil end            -- the controller's own computer
  if f.getRecipes then return "machine" end
  if f.transferItem then return f.canOutput and "splitter" or "merger" end
  if f.getInventories then return "container" end
  return nil
end

-- ordinal of connector `conn` among `ownerProxy`'s connectors of `dir`
local function portIndex(ownerProxy, conn, dir)
  local idx = -1
  for _, c in ipairs(ownerProxy:getFactoryConnectors()) do
    if c.direction == dir then idx = idx + 1; if c == conn then return idx end end
  end
  return 0
end

-- a component's class never changes, and reflection (getFunctions over the hierarchy)
-- is not free — cache the role per id so the persistent loop's periodic re-discovery
-- doesn't re-introspect every component every tick. `false` = known not-a-node.
Discover._roleCache = {}
function Discover.roleCached(id, p)
  local r = Discover._roleCache[id]
  if r == nil then r = Discover.classify(p) or false; Discover._roleCache[id] = r end
  return r or nil
end

function Discover.run(opts)
  opts = opts or {}
  local find = opts.find or function(q) return component.findComponent(q) end
  local getProxy = opts.getProxy or function(id) return component.proxy(id) end

  local topo = { containers = {}, splitters = {}, mergers = {}, constructors = {}, belts = {} }
  local proxies = {}
  for _, id in ipairs(find("")) do
    local p = getProxy(id)
    if p then
      local role = Discover.roleCached(id, p)
      if role then
        proxies[id] = p
        if role == "splitter" then topo.splitters[#topo.splitters + 1] = id
        elseif role == "merger" then topo.mergers[#topo.mergers + 1] = id
        elseif role == "machine" then topo.constructors[#topo.constructors + 1] = id
        elseif role == "container" then topo.containers[#topo.containers + 1] = { id = id } end
      end
    end
  end

  for id, p in pairs(proxies) do
    if p.getFactoryConnectors then
      local outIdx = -1
      for _, c in ipairs(p:getFactoryConnectors()) do
        if c.direction == OUTPUT then
          outIdx = outIdx + 1
          if c.isConnected then
            local peer = c:getConnected()
            local owner = peer and peer.owner
            if owner and owner.isNetworkComponent and proxies[owner.id] then
              topo.belts[#topo.belts + 1] = {
                from = id, fromOutput = outIdx,
                to = owner.id, toInput = portIndex(owner, peer, INPUT),
              }
            end
          end
        end
      end
    end
  end
  return topo
end

return Discover
end
_preload["router"] = function()
-- router.lua — topology-aware item routing framework for FicsIt-Networks.
--
-- This is PRODUCT code: it runs in-game on a Computer Case as well as under the
-- devbox emulator. The topology can be auto-discovered (lib/discover.lua crawls the
-- belt graph via getFactoryConnectors -> getConnected -> owner) or DECLARED as data;
-- either way the router DISCOVERS routes through it with breadth-first search:
--
--     order("iron ingot", 100, "OUT_IRON")
--
-- finds the path from the container that provides the item to the target container
-- and programs every CodeableSplitter along the way to send that item type out the
-- correct port. CodeableMergers just pass through. Works for any topology.
--
-- Topology shape:
--   {
--     containers = { {id=, provides=?, buffer=?, output=?, target=?, isDefault=?}, ... },
--                  -- provides: item this source emits; buffer/output: dest item;
--                  -- target: fill cap; isDefault: a DEFAULT_OUT catch-all sink
--     splitters  = { "S1", ... },                          -- CodeableSplitter ids/nicks
--     mergers    = { "M1", ... },                          -- CodeableMerger ids/nicks
--     belts      = { {from=, to=, fromOutput=?, toInput=?}, ... },  -- directed, port-aware
--   }
--
-- Resolution of an id to a live component proxy is pluggable (default component.proxy)
-- so the same code drives the emulator and a real network.

local Router = {}
Router.__index = Router

-- Case-insensitive item names: FIN reflection returns canonical (Title) case
-- ("Iron Plate"), nicks give lowercase. Normalize everything to lowercase so keys
-- and comparisons match regardless of source.
local function lc(s) return s and tostring(s):lower() or nil end
-- name of an item from a FIN signal payload (FInventoryItem: .type is an ItemType
-- OBJECT with .name) — tolerant of the emulator/legacy {type=string} shape too.
local function itemName(it)
  if type(it) ~= "table" then return lc(it) end
  local t = it.type
  if type(t) == "table" then return lc(t.name) end
  return lc(t)
end

-- Resolve a container's destination item + ordinal + optional fill target, from an
-- explicit c.buffer / c.output item field or its name <Item>_(Buffer|Output)_<n>[_<target>]
-- (case-insensitive). Returns item, n, target — or nil if not a destination.
function Router.destItem(c)
  if c.buffer then return tostring(c.buffer):lower(), c.n end
  if c.output then return tostring(c.output):lower(), c.n end
  -- with explicit target suffix: <prefix>_<kw>_<index>_<target>
  local prefix, kw, n, tgt = tostring(c.id):match("^(.-)_(%a+)_(%d+)_(%d+)$")
  if not (prefix and (kw:lower() == "buffer" or kw:lower() == "output")) then
    prefix, kw, n = tostring(c.id):match("^(.-)_(%a+)_(%d+)$"); tgt = nil
  end
  if prefix and (kw:lower() == "buffer" or kw:lower() == "output") then
    return prefix:gsub("_", " "):lower(), tonumber(n), tgt and tonumber(tgt) or nil
  end
  return nil
end

function Router.new(topology, getProxy)
  local self = setmetatable({}, Router)
  self.topo = topology
  self.getProxy = getProxy or function(id) return component.proxy(id) end
  self.isSplitter, self.isMerger = {}, {}
  for _, id in ipairs(topology.splitters or {}) do self.isSplitter[id] = true end
  for _, id in ipairs(topology.mergers or {}) do self.isMerger[id] = true end
  -- adjacency: node -> list of belts leaving it
  self.adj = {}
  for _, b in ipairs(topology.belts or {}) do
    self.adj[b.from] = self.adj[b.from] or {}
    table.insert(self.adj[b.from], b)
  end
  -- route[splitterId][itemType] = { output=portIndex, order=orderRef, terminal=bool }
  self.route = {}
  self.orders = {}
  -- gated source release: a networked source container feeding a merger input only
  -- releases items when an order calls for them. gated[mergerId][input] = item type.
  self.sourceItem = {}
  for _, c in ipairs(topology.containers or {}) do
    if c.provides then self.sourceItem[c.id] = lc(c.provides) end
  end
  self.gated = {}
  for _, b in ipairs(topology.belts or {}) do
    if self.sourceItem[b.from] and self.isMerger[b.to] then
      self.gated[b.to] = self.gated[b.to] or {}
      self.gated[b.to][b.toInput or 0] = self.sourceItem[b.from]
    end
  end
  -- containers named DEFAULT_OUT_<n> are the catch-all sinks for unroutable items.
  self.defaults = {}
  for _, c in ipairs(topology.containers or {}) do
    -- by name in declared mode, or the c.isDefault flag in auto-discovered mode
    if c.isDefault or tostring(c.id):match("^DEFAULT_OUT_%d+$") then table.insert(self.defaults, c.id) end
  end
  -- buffer/output destinations: an explicit c.buffer / c.output item (e.g. set by
  -- the namer's auto-assignment) OR a name <Item>_(Buffer|Output)_<n>. item +
  -- capacity, grouped per item, numerically ordered.
  self.bufferItem = {}            -- destId -> item
  self.capacity = {}              -- destId -> max units (defaults to its target)
  self.buffersForItem = {}        -- item -> { destId... } ordered by <n>
  local order_n = {}
  for _, c in ipairs(topology.containers or {}) do
    local item, n, tgt = Router.destItem(c)
    if item then
      self.bufferItem[c.id] = item
      self.capacity[c.id] = c.capacity or c.target or tgt
      self.buffersForItem[item] = self.buffersForItem[item] or {}
      table.insert(self.buffersForItem[item], c.id)
      order_n[c.id] = n or 1
    end
  end
  for _, list in pairs(self.buffersForItem) do
    table.sort(list, function(x, y) return order_n[x] < order_n[y] end)
  end
  self.ordersByItem = {}          -- item -> order (latest placed)
  self._fh = {}                   -- firstHop cache: [from][dst] = belt | false
  return self
end

-- Find the container that emits `item` (declared via `provides`).
function Router:sourceOf(item)
  item = lc(item)
  for _, c in ipairs(self.topo.containers or {}) do
    if lc(c.provides) == item then return c.id end
  end
end

-- Breadth-first search src -> dst over the belt graph. Returns the ordered list of
-- belts forming the path, or nil if unreachable.
function Router:findPath(src, dst)
  local prev, seen, queue, head = {}, { [src] = true }, { src }, 1
  while head <= #queue do
    local node = queue[head]; head = head + 1
    if node == dst then break end
    for _, b in ipairs(self.adj[node] or {}) do
      if not seen[b.to] then
        seen[b.to] = true
        prev[b.to] = b
        queue[#queue + 1] = b.to
      end
    end
  end
  if not prev[dst] and src ~= dst then return nil end
  local path, node = {}, dst
  while prev[node] do
    table.insert(path, 1, prev[node])
    node = prev[node].from
  end
  return path
end

--- Route `count` of `item` to `dst`. Discovers the path and programs every
--- splitter on it. `src` is optional — if omitted, the container declared to
--- `provide` the item is used (the double-pass production case passes the
--- constructor as the explicit src for the crafted product). Returns true, or
--- false + reason if no path/source.
function Router:order(item, count, dst, src)
  item = lc(item)
  src = src or self:sourceOf(item)
  if not src then return false, "no source provides " .. item end
  if not self:findPath(src, dst) then return false, ("no path %s -> %s"):format(src, dst) end
  local order = { item = item, count = count, dst = dst, src = src, delivered = 0, rerouted = 0, released = 0 }
  table.insert(self.orders, order)
  self.ordersByItem[item] = order
  return true
end

-- Cached first belt of a shortest path from -> dst (nil if unreachable). Works on
-- the belt LOOP because findPath's BFS handles cycles.
function Router:firstHopTo(from, dst)
  self._fh[from] = self._fh[from] or {}
  local hit = self._fh[from][dst]
  if hit ~= nil then return hit or nil end
  local path = self:findPath(from, dst)
  local belt = (path and path[1]) or false
  self._fh[from][dst] = belt
  return belt or nil
end

-- Current units of `item` in a destination (FIN-faithful inventory read).
function Router:_count(dst, item)
  local p = self.getProxy(dst)
  if not p or not p.getInventories then return 0 end
  local total = 0
  item = lc(item)
  for _, inv in ipairs(p:getInventories()) do
    for i = 0, (inv.size or 0) - 1 do
      local s = inv:getStack(i)
      -- empty slots return a 0-count stack with a nil item.type in-game — guard it
      if s and (s.count or 0) > 0 and s.item and s.item.type and lc(s.item.type.name) == item then
        total = total + s.count
      end
    end
  end
  return total
end

-- Does a destination have room for one more of `item`? Non-buffer dests
-- (constructor, sink) always accept.
function Router:hasRoom(dst, item)
  local cap = self.capacity[dst]
  if not cap then return true end
  return self:_count(dst, item) < cap
end

--- Handle one ItemRequest. Separated from install() so a long-lived listener can
--- delegate to the CURRENT router after a live re-discovery (App swaps the router
--- instance without re-registering — avoids stacking duplicate listeners).
--- FIN signal payload is an FInventoryItem; the item name is item.type.name
--- (item.type is the ItemType OBJECT, not a string). itemName() normalizes to
--- lowercase so matching is case-insensitive vs reflection's canonical (Title) case.
function Router:_dispatch(sender, a, b)
  local id = sender.id
  if self.isSplitter[id] then
    self:_routeAtSplitter(sender, id, itemName(a))     -- splitter sig: (item)
  elseif self.isMerger[id] then
    local input, item = a, b                           -- merger sig: (input, item)
    if self.gated[id] and self.gated[id][input] ~= nil then
      -- Gated networked source: release ONLY what an order still wants, so the
      -- container outputs exactly what's ordered and otherwise stays stopped.
      local ord = self:_needRelease(itemName(item))
      -- count a release ONLY when the pull actually succeeds (transferItem can fail
      -- under back-pressure when the merger output is full) — else the counter
      -- over-reports and the source stops short.
      if ord and sender:transferItem(input) then
        ord.released = ord.released + 1
      end
      -- else: do not pull -> the container holds its items (stopped)
    else
      sender:transferItem(input)                       -- in-transit: always forward
    end
  end
end

--- Register the signal handler that executes routing. Call once, then pump the
--- event loop (e.g. Router:run() or your own event.pull loop).
function Router:install()
  event.registerListener(event.filter{ event = "ItemRequest" },
    function(_, sender, a, b) self:_dispatch(sender, a, b) end)
end

-- An active order for this item type that still has items left to release.
function Router:_needRelease(itemType)
  for _, o in ipairs(self.orders) do
    if o.item == itemType and o.released < o.count then return o end
  end
end

--- Level-triggered kick for gated sources. ItemRequest is EDGE-triggered (fires once,
--- when an item arrives at a merger input); an item that arrives while no order wants
--- it just sits there, and is never re-offered when a LATER order does want it — so
--- between orders the 2-slot merger input can stay stuck and block its source. After
--- (re)planning, call this to poll every gated input and release whatever an active
--- order now needs (until outputs back-pressure). Idempotent; safe to call each tick.
function Router:pumpGated()
  local progressed = true
  while progressed do
    progressed = false
    for id, inputs in pairs(self.gated) do
      local sender = self.getProxy(id)
      if sender and sender.getInput then
        for input in pairs(inputs) do
          local it = sender:getInput(input)
          local ord = it and self:_needRelease(itemName(it))
          if ord and sender:transferItem(input) then
            ord.released = ord.released + 1
            progressed = true
          end
        end
      end
    end
  end
end

-- Decide where an item at a splitter goes, checking destination ROOM and
-- rerouting on the loop when a buffer is full:
--   1. the item's primary buffer (the order's dst), then any OTHER buffer for the
--      same item, in number order — first one that is reachable and has room;
--   2. for a non-buffer target (constructor/sink) just route to it (always accepts);
--   3. last resort: the DEFAULT_OUT sink;
--   4. nothing reachable: jam + panic.
-- Because the belts form a loop, every buffer is reachable from every splitter, so
-- an item whose nearest buffer is full is forwarded on toward an alternate.
function Router:_routeAtSplitter(sender, id, item)
  local ord = self.ordersByItem[item]
  local targets, skipRoom = {}, false
  if ord and not self.bufferItem[ord.dst] then
    targets, skipRoom = { ord.dst }, true            -- non-buffer dst (constructor): always accepts
  else
    local prim = ord and ord.dst
    if prim and self.bufferItem[prim] then targets[#targets + 1] = prim end
    for _, b in ipairs(self.buffersForItem[item] or {}) do
      if b ~= prim then targets[#targets + 1] = b end
    end
  end

  for _, D in ipairs(targets) do
    local belt = self:firstHopTo(id, D)
    if belt and (skipRoom or self:hasRoom(D, item)) then
      -- only act/count when the transfer succeeds; if the chosen output is full
      -- (back-pressure) leave the item — the engine re-fires ItemRequest when the
      -- output drains, giving a retry.
      if sender:transferItem(belt.fromOutput or 0) then
        if belt.to == D and ord then                 -- delivered directly this hop
          if D == ord.dst then ord.delivered = ord.delivered + 1
          else ord.rerouted = ord.rerouted + 1 end
        end
      end
      return
    end
  end

  -- last resort: the catch-all sink
  local sink = self.defaults[1]
  if sink then
    local belt = self:firstHopTo(id, sink)
    if belt then sender:transferItem(belt.fromOutput or 0); return end
  end
  computer.panic(("unroutable item '%s' at splitter %s: add a container named DEFAULT_OUT_%d and wire it into the network")
    :format(tostring(item), id, #self.defaults + 1))
end

--- Are all placed orders fulfilled (delivered to their primary dst)?
function Router:allDone()
  for _, o in ipairs(self.orders) do
    if o.delivered < o.count then return false end
  end
  return true
end

--- Drive the event loop until the system is quiescent (every item settled into a
--- buffer or the sink, every gated source stopped). Returns true when quiescent.
function Router:run(maxLoops)
  for _ = 1, maxLoops or 5000000 do
    if event.pull(0) == nil then return true end   -- nil => queue empty and nothing left to flow
  end
  return false
end

return Router
end
_preload["planner"] = function()
-- planner.lua — production planner for FicsIt-Networks (PRODUCT code, runs in-game).
--
-- Sits on top of router.lua. It:
--   * auto-detects constructors and reads their recipes via reflection
--     (getRecipes -> getIngredients/getProducts, with item names AND counts) — no
--     hardcoded recipe data.
--   * derives each buffer's wanted item from its label: <ITEM>_BUFFER_<n>
--     (IRON_PLATE_BUFFER_1 -> "iron plate", REANIMATED_SAM_BUFFER_1 -> "reanimated sam").
--   * keeps buffers topped up: for each buffer it computes need = target - current,
--     finds how to make the item, and places orders so it flows to the buffer.
--   * supports MULTIPLE recipes per item and picks intelligently:
--       - if a recipe can fully satisfy the need from available stock, pick the
--         most input-efficient one (max output / input).
--       - otherwise pick the one that yields the MOST from what's available.
--   * drives the double pass: order ingredients -> constructor, then the crafted
--     product (source = constructor) -> buffer.

local Planner = {}
Planner.__index = Planner

local function ceil(a, b) return math.floor((a + b - 1) / b) end
-- Case-insensitive item names: reflection gives canonical (Title) case, nicks give
-- lowercase. Key/compare everything lowercase so they match. (See router.lua.)
local function lc(s) return s and tostring(s):lower() or nil end

function Planner.new(topology, router, getProxy)
  local self = setmetatable({}, Planner)
  self.topo = topology
  self.router = router
  self.getProxy = getProxy or function(id) return component.proxy(id) end
  self.recipesByProduct = {}     -- itemName -> list of recipe options
  self.busy = {}                 -- ctorId -> true once assigned this planning pass
  self.sources = {}              -- itemName -> source container id (declared provides)
  for _, c in ipairs(topology.containers or {}) do
    if c.provides then self.sources[lc(c.provides)] = c.id end
  end
  return self
end

-- ---- reflection: discover constructors + recipes ---------------------------
function Planner:scan()
  for _, cid in ipairs(self.topo.constructors or {}) do
    local ctor = self.getProxy(cid)
    for _, recipe in ipairs(ctor:getRecipes()) do
      local ings = {}
      local totalIn = 0
      for _, ia in ipairs(recipe:getIngredients()) do
        ings[#ings + 1] = { name = lc(ia.type.name), amount = ia.amount }
        totalIn = totalIn + ia.amount
      end
      local duration = recipe.duration or 1
      for _, pa in ipairs(recipe:getProducts()) do
        local key = lc(pa.type.name)
        local list = self.recipesByProduct[key] or {}
        list[#list + 1] = {
          recipe = recipe, ctorId = cid, ctor = ctor,
          out = pa.amount, ingredients = ings, totalIn = totalIn,
          duration = duration,
          throughput = pa.amount / duration,   -- output per minute decides when stock is plentiful
        }
        self.recipesByProduct[key] = list
      end
    end
  end
end

-- ---- inventory reads (FIN-faithful: getInventories -> getStack) -------------
local function count_in(proxy, item)
  item = lc(item)
  local invs = proxy:getInventories()
  local total = 0
  for _, inv in ipairs(invs) do
    for i = 0, (inv.size or 0) - 1 do
      local stack = inv:getStack(i)
      -- in-game an empty slot returns a 0-count stack whose item.type is nil — guard
      if stack and (stack.count or 0) > 0 and stack.item and stack.item.type
         and lc(stack.item.type.name) == item then
        total = total + stack.count
      end
    end
  end
  return total
end

-- total available of an item across all declared source containers
function Planner:available(item)
  item = lc(item)
  local n = 0
  for _, c in ipairs(self.topo.containers or {}) do
    if lc(c.provides) == item then n = n + count_in(self.getProxy(c.id), item) end
  end
  return n
